module RefModule (
    input clk,
    input rst,
    input load,
    input [7:0] data_in,
    output reg [7:0] reg_out);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            reg_out <= 8'b00000000;
        else if (load)
            reg_out <= data_in;
    end

endmodule
